1. <?php
2. 
3. declare(strict_types=1);
4. 
5. namespace Revolution\Fullfeed;
6. 
7. use Illuminate\Support\Collection;
8. use Illuminate\Support\Facades\Http;
9. use Illuminate\Support\Facades\Pipeline;
10. use Illuminate\Support\Str;
11. use Revolution\Fullfeed\Extractor\SelectorExtractor;
12. use Revolution\Fullfeed\Extractor\XPathExtractor;
13. 
14. class FullFeedClient
15. {
16.     public function __construct(
17.         private array $items = [],
18.     ) {}
19. 
20.     /**
21.      * Get the content of the URL and return the part specified by data.selector or data.xpath.
22.      *
23.      * URLのコンテンツを取得し、data.selectorやdata.xpathで指定された部分を返す
24.      */
25.     public function get(string $url): string
26.     {
27.         $response = Http::when(
28.             filled(config('fullfeed.user_agent')),
29.             fn ($client) => $client->withUserAgent(config('fullfeed.user_agent')),
30.         )->get($url);
31. 
32.         if ($response->failed()) {
33.             return '';
34.         }
35. 
36.         return $this->extract($response->body(), $url);
37.     }
38. 
39.     /**
40.      * Extract the part specified by data.selector or data.xpath from the given HTML data.
41.      *
42.      * 与えられたHTMLデータから、data.selectorやdata.xpathで指定された部分を抽出する
43.      */
44.     public function extract(string $source, string $url): string
45.     {
46.         $rule = $this->first($url);
47.         if (blank($rule)) {
48.             return '';
49.         }
50. 
51.         $context = new Context(
52.             source: $source,
53.             url: $url,
54.             rule: $rule,
55.         );
56. 
57.         $pipes = Collection::wrap(data_get($rule, 'data.callable'))
58.             ->push(XPathExtractor::class)
59.             ->push(SelectorExtractor::class)
60.             ->merge(data_get($rule, 'data.after_callable'))
61.             ->toArray();
62. 
63.         return Pipeline::send($context)
64.             ->through($pipes)
65.             ->thenReturn()
66.             ->source;
67.     }
68. 
69.     /**
70.      * Ensure there is a rule corresponding to the URL using data.url regex.
71.      *
72.      * data.urlの正規表現を使って、URLに対応するルールが存在するか確認する
73.      */
74.     public function has(string $url): bool
75.     {
76.         return array_any($this->items, fn ($item) => Str::isMatch('@'.data_get($item, 'data.url').'@i', $url));
77.     }
78. 
79.     /**
80.      * Get first rule data corresponding to the URL.
81.      *
82.      * URLに対応する最初のルールデータを取得
83.      */
84.     public function first(string $url): ?array
85.     {
86.         return array_find($this->items, fn ($item) => Str::isMatch('@'.data_get($item, 'data.url').'@i', $url));
87.     }
88. 
89.     /**
90.      * Merge new items to the beginning of the existing items.
91.      */
92.     public function merge(array $items): static
93.     {
94.         $this->items = array_merge($items, $this->items);
95. 
96.         return $this;
97.     }
98. 
99.     public function all(): array
100.     {
101.         return $this->items;
102.     }
103. 
104.     public function toArray(): array
105.     {
106.         return $this->items;
107.     }
108. 
109.     public function collect(): Collection
110.     {
111.         return new Collection($this->items);
112.     }
